import{_ as a,c as s,o as i,ak as r,al as t}from"./chunks/framework.DHLlVITf.js";const m=JSON.parse('{"title":"AireAssert Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireassert-v1-3-3.md","filePath":"aireblock-releases/aireassert-v1-3-3.md","lastUpdated":1784881015000}'),o={name:"aireblock-releases/aireassert-v1-3-3.md"};function l(n,e,c,d,h,p){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="aireassert-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+t+'"> AireAssert Release Notes</span> <a class="header-anchor" href="#aireassert-release-notes" aria-label="Permalink to “AireAssert Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.3.3<br><strong>Release Date:</strong> 24 July 2026</p></blockquote><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Enhanced Session Token Security (AA-903)</li><li>Improved Form URL Resolution (AA-986)</li><li>Upgraded to .NET 10 (AA-988)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Repository Refresh (AA-984)</li><li>Improved Test Reliability (AA-990)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="enhanced-session-token-security-aa-903" tabindex="-1">Enhanced Session Token Security (AA-903) <a class="header-anchor" href="#enhanced-session-token-security-aa-903" aria-label="Permalink to “Enhanced Session Token Security (AA-903)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Session handling has moved to a Backend-for-Frontend (BFF) approach, removing session tokens from URLs.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your session tokens are no longer exposed in page URLs, reducing the chance they could be leaked through browser history, logs, or shared links, keeping your account safer.</p></div><h4 id="improved-form-url-resolution-aa-986" tabindex="-1">Improved Form URL Resolution (AA-986) <a class="header-anchor" href="#improved-form-url-resolution-aa-986" aria-label="Permalink to “Improved Form URL Resolution (AA-986)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where retrieving a form URL from an AireFrame action would fail if no version was included in the reference. Versionless form references are now handled correctly.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Forms accessed via actions now open reliably, even when a specific version isn&#39;t specified, so you&#39;re less likely to hit a failed link.</p></div><h4 id="upgraded-to-net-10-aa-988" tabindex="-1">Upgraded to .NET 10 (AA-988) <a class="header-anchor" href="#upgraded-to-net-10-aa-988" aria-label="Permalink to “Upgraded to .NET 10 (AA-988)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireAssert has been upgraded to run on .NET 10, keeping the platform on a current, supported runtime.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll benefit from the ongoing performance, security, and reliability improvements that come with staying on a current, supported platform.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-repository-refresh-aa-984" tabindex="-1">Fixed Repository Refresh (AA-984) <a class="header-anchor" href="#fixed-repository-refresh-aa-984" aria-label="Permalink to “Fixed Repository Refresh (AA-984)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Resolved an intermittent issue where using the refresh button in the AireAssert UI would occasionally fail to refresh the repository.</p></div><h4 id="improved-test-reliability-aa-990" tabindex="-1">Improved Test Reliability (AA-990) <a class="header-anchor" href="#improved-test-reliability-aa-990" aria-label="Permalink to “Improved Test Reliability (AA-990)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a flaky automated test that could fail intermittently, improving the consistency and reliability of our test suite.</p></div>',24)])])}const f=a(o,[["render",l]]);export{m as __pageData,f as default};
